/*
 * fmin() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x, double y)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += fmin(vx, vy);
#else
    double r = fmin(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values — NaN/Inf/zero combos (14) --- */
    emit(0.0, 0.0);                                                              /* +0, +0 */
    emit(-0.0, 0.0);                                                             /* -0, +0: fmin returns either zero */
    emit(0.0, -0.0);                                                             /* +0, -0 */
    emit(-0.0, -0.0);                                                            /* -0, -0 */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);                        /* qNaN, 1.0: returns 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);                        /* sNaN, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);                        /* -qNaN, 1.0: returns 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);                        /* 1.0, qNaN: returns 1.0 */
    emit_u(0x7ff8000000000000ULL, 0x7ff8000000000000ULL);                        /* qNaN, qNaN */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);                        /* +Inf, 1.0: returns 1.0 */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);                        /* -Inf, 1.0: returns -Inf */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);                        /* 1.0, +Inf: returns 1.0 */
    emit_u(0x3ff0000000000000ULL, 0xfff0000000000000ULL);                        /* 1.0, -Inf: returns -Inf */
    emit_u(0x7ff0000000000000ULL, 0xfff0000000000000ULL);                        /* +Inf, -Inf: returns -Inf */

    /* --- Section 2: Subnormal (denormal) pairs (8) --- */
    emit_u(0x0000000000000001ULL, 0x0000000000000000ULL);                        /* min positive subnormal, +0 */
    emit_u(0x8000000000000001ULL, 0x0000000000000000ULL);                        /* min negative subnormal, +0 */
    emit_u(0x0008000000000000ULL, 0x0000000000000000ULL);                        /* mid positive subnormal, +0 */
    emit_u(0x8008000000000000ULL, 0x0000000000000000ULL);                        /* mid negative subnormal, +0 */
    emit_u(0x000fffffffffffffULL, 0x0000000000000000ULL);                        /* max positive subnormal, +0 */
    emit_u(0x800fffffffffffffULL, 0x0000000000000000ULL);                        /* max negative subnormal, +0 */
    emit_u(0x0000000000000001ULL, 0x8000000000000001ULL);                        /* min +subnormal, min -subnormal */
    emit_u(0x000fffffffffffffULL, 0x800fffffffffffffULL);                        /* max +subnormal, max -subnormal */

    /* --- Section 3: Normal boundary pairs (6) --- */
    emit(DBL_MIN, 0.0);                                                          /* 2^-1022, +0 */
    emit(-DBL_MIN, 0.0);                                                         /* -2^-1022, +0 */
    emit_u(0x0010000000000001ULL, 0x0010000000000000ULL);                        /* one ULP above DBL_MIN, DBL_MIN */
    emit(DBL_MAX, 1.0);                                                          /* DBL_MAX, 1.0: returns 1.0 */
    emit(-DBL_MAX, 1.0);                                                         /* -DBL_MAX, 1.0: returns -DBL_MAX */
    emit(DBL_MAX, -DBL_MAX);                                                     /* DBL_MAX, -DBL_MAX: returns -DBL_MAX */

    /* --- Section 4: Near 1.0 — ULP neighborhood (10) --- */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);                        /* one ULP below 1.0, 1.0 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);                        /* one ULP above 1.0, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x3fefffffffffffffULL);                        /* 1.0, one ULP below 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x3ff0000000000001ULL);                        /* 1.0, one ULP above 1.0 */
    emit(1.0, 1.0);                                                              /* exact equal 1.0 */
    emit(-1.0, -1.0);                                                            /* exact equal -1.0 */
    emit_u(0xbfefffffffffffffULL, 0xbff0000000000000ULL);                        /* one ULP toward zero from -1.0, -1.0 */
    emit_u(0xbff0000000000001ULL, 0xbff0000000000000ULL);                        /* one ULP away from -1.0, -1.0 */
    emit(1.0, -1.0);                                                             /* 1.0, -1.0: returns -1.0 */
    emit(-1.0, 1.0);                                                             /* -1.0, 1.0: returns -1.0 */

    /* --- Section 5: Equal value pairs (6) --- */
    emit(0.5, 0.5);
    emit(2.0, 2.0);
    emit(3.14159265358979, 3.14159265358979);
    emit(1.0e10, 1.0e10);
    emit(-0.5, -0.5);
    emit(-2.0, -2.0);

    /* --- Section 6: Positive asymmetric pairs (12) --- */
    emit(1.0, 2.0);                                                              /* x < y */
    emit(2.0, 1.0);                                                              /* x > y */
    emit(0.5, 1.5);
    emit(1.5, 0.5);
    emit(10.0, 20.0);
    emit(20.0, 10.0);
    emit(100.0, 50.0);
    emit(50.0, 100.0);
    emit(1.0e100, 1.0e50);
    emit(1.0e50, 1.0e100);
    emit(1.0e300, 1.0e200);
    emit(1.0e200, 1.0e300);

    /* --- Section 7: Negative asymmetric pairs (8) --- */
    emit(-1.0, -2.0);                                                            /* x > y (less negative) */
    emit(-2.0, -1.0);                                                            /* x < y (more negative) */
    emit(-0.5, -1.5);
    emit(-1.5, -0.5);
    emit(-10.0, -20.0);
    emit(-20.0, -10.0);
    emit(-1.0e100, -1.0e50);
    emit(-1.0e50, -1.0e100);

    /* --- Section 8: Mixed-sign pairs (10) --- */
    emit(-1.0, 1.0);
    emit(1.0, -1.0);
    emit(-2.0, 2.0);
    emit(2.0, -2.0);
    emit(-0.5, 0.5);
    emit(0.5, -0.5);
    emit(-1.0e10, 1.0e10);
    emit(1.0e10, -1.0e10);
    emit(-DBL_MAX, DBL_MAX);
    emit(DBL_MAX, -DBL_MAX);

    /* --- Section 9: Large and extreme pairs (10) --- */
    emit(DBL_MAX, DBL_MAX);
    emit(-DBL_MAX, -DBL_MAX);
    emit(1.0e300, -1.0e300);
    emit(-1.0e300, 1.0e300);
    emit(1.7976931348623157e308, 1.7976931348623156e308);                        /* DBL_MAX and one ULP below */
    emit(1.0e15, 1.0e16);
    emit(1.0e16, 1.0e15);
    emit(-1.0e15, -1.0e16);
    emit(-1.0e16, -1.0e15);
    emit(1.23456789012345e15, -9.87654321098765e14);                             /* large mixed magnitudes */

    /* --- Section 10: Zero-crossing and magnitude spread (16) --- */
    emit(0.0, 1.0);
    emit(1.0, 0.0);
    emit(0.0, -1.0);
    emit(-1.0, 0.0);
    emit(-0.0, 1.0);
    emit(1.0, -0.0);
    emit(-0.0, -1.0);
    emit(-1.0, -0.0);
    emit(1.0e-300, 1.0e-200);
    emit(1.0e-200, 1.0e-300);
    emit(-1.0e-300, -1.0e-200);
    emit(-1.0e-200, -1.0e-300);
    emit(1.0e-10, -1.0e-10);
    emit(-1.0e-10, 1.0e-10);
    emit(DBL_MIN, DBL_MIN);
    emit(-DBL_MIN, -DBL_MIN);
}

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += fmin(x+i, x+i+1.0);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0);
#else
    test_representative_100();
    test_sweep();
    test_random_300();
#endif
    return 0;
}

